/*
 * Segregated explicit free-list allocator with boundary-tag coalescing.
 * Free-list heads are stored in heap memory to respect the assignment rule
 * against global arrays/structs.
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

team_t team = {
	"BSCS Bench",
	"BSCS Bench Agent",
	"bscs1",
	"",
	""
};

#define WSIZE sizeof(uintptr_t)
#define DSIZE (2 * WSIZE)
#define CHUNKSIZE (1 << 12)
#define LISTLIMIT 16
#define MINBLOCKSIZE (4 * WSIZE)

#define MAX(x, y) ((x) > (y) ? (x) : (y))
#define ALIGN(size) (((size) + (DSIZE - 1)) & ~(DSIZE - 1))
#define PACK(size, alloc) ((size) | (alloc))

#define GET(p) (*(uintptr_t *)(p))
#define PUT(p, val) (*(uintptr_t *)(p) = (uintptr_t)(val))

#define GET_SIZE(p) (GET(p) & ~(DSIZE - 1))
#define GET_ALLOC(p) (GET(p) & 0x1)

#define HDRP(bp) ((char *)(bp) - WSIZE)
#define FTRP(bp) ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)
#define NEXT_BLKP(bp) ((char *)(bp) + GET_SIZE(HDRP(bp)))
#define PREV_BLKP(bp) ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

#define NEXT_FREEP(bp) (*(void **)(bp))
#define PREV_FREEP(bp) (*(void **)((char *)(bp) + WSIZE))

static char *heap_listp;
static void *seglist_base;

static int class_index(size_t size);
static size_t adjust_block_size(size_t size);
static void *extend_heap(size_t words);
static void *coalesce(void *bp);
static void *find_fit(size_t asize);
static void place(void *bp, size_t asize);
static void insert_free_block(void *bp);
static void remove_free_block(void *bp);
static void *list_head(int index);
static void set_list_head(int index, void *bp);
static bool in_heap(const void *p);
static bool aligned(const void *p);
static void checkblock(void *bp);
static void printblock(void *bp);

static int
class_index(size_t size)
{
	int index = 0;
	size_t bound = MINBLOCKSIZE;

	while (index < LISTLIMIT - 1 && size > bound) {
		bound <<= 1;
		index++;
	}
	return (index);
}

static size_t
adjust_block_size(size_t size)
{
	if (size == 0)
		return (0);
	return (MAX(ALIGN(size + DSIZE), MINBLOCKSIZE));
}

static void *
list_head(int index)
{
	return (((void **)seglist_base)[index]);
}

static void
set_list_head(int index, void *bp)
{
	((void **)seglist_base)[index] = bp;
}

static void
insert_free_block(void *bp)
{
	int index = class_index(GET_SIZE(HDRP(bp)));
	void *head = list_head(index);

	NEXT_FREEP(bp) = head;
	PREV_FREEP(bp) = NULL;
	if (head != NULL)
		PREV_FREEP(head) = bp;
	set_list_head(index, bp);
}

static void
remove_free_block(void *bp)
{
	int index = class_index(GET_SIZE(HDRP(bp)));
	void *prev = PREV_FREEP(bp);
	void *next = NEXT_FREEP(bp);

	if (prev != NULL)
		NEXT_FREEP(prev) = next;
	else
		set_list_head(index, next);

	if (next != NULL)
		PREV_FREEP(next) = prev;
}

int
mm_init(void)
{
	size_t initial_words = LISTLIMIT + 4;
	char *base;

	if ((base = mem_sbrk(initial_words * WSIZE)) == (void *)-1)
		return (-1);

	PUT(base, 0);
	seglist_base = base + WSIZE;
	for (int i = 0; i < LISTLIMIT; i++)
		set_list_head(i, NULL);

	PUT(base + (LISTLIMIT + 1) * WSIZE, PACK(DSIZE, 1));
	PUT(base + (LISTLIMIT + 2) * WSIZE, PACK(DSIZE, 1));
	PUT(base + (LISTLIMIT + 3) * WSIZE, PACK(0, 1));

	heap_listp = base + (LISTLIMIT + 2) * WSIZE;
	return (extend_heap(CHUNKSIZE / WSIZE) != NULL ? 0 : -1);
}

static void *
extend_heap(size_t words)
{
	size_t size;
	void *bp;

	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if (size < MINBLOCKSIZE)
		size = MINBLOCKSIZE;

	if ((bp = mem_sbrk((intptr_t)size)) == (void *)-1)
		return (NULL);

	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));
	return (coalesce(bp));
}

static void *
coalesce(void *bp)
{
	bool prev_alloc = GET_ALLOC(FTRP(PREV_BLKP(bp)));
	bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));
	size_t size = GET_SIZE(HDRP(bp));

	if (!prev_alloc) {
		void *prev_bp = PREV_BLKP(bp);
		remove_free_block(prev_bp);
		size += GET_SIZE(HDRP(prev_bp));
		PUT(HDRP(prev_bp), PACK(size, 0));
		PUT(FTRP(bp), PACK(size, 0));
		bp = prev_bp;
	}

	if (!next_alloc) {
		void *next_bp = NEXT_BLKP(bp);
		remove_free_block(next_bp);
		size += GET_SIZE(HDRP(next_bp));
		PUT(HDRP(bp), PACK(size, 0));
		PUT(FTRP(next_bp), PACK(size, 0));
	}

	insert_free_block(bp);
	return (bp);
}

static void *
find_fit(size_t asize)
{
	int index = class_index(asize);

	for (int i = index; i < LISTLIMIT; i++) {
		void *bp = list_head(i);
		void *best = NULL;
		size_t best_size = ~(size_t)0;
		int examined = 0;

		while (bp != NULL) {
			size_t block_size = GET_SIZE(HDRP(bp));

			if (block_size >= asize) {
				if (block_size == asize)
					return (bp);
				if (block_size < best_size) {
					best = bp;
					best_size = block_size;
				}
				if (examined >= 7)
					break;
			}
			bp = NEXT_FREEP(bp);
			examined++;
		}
		if (best != NULL)
			return (best);
	}
	return (NULL);
}

static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));

	remove_free_block(bp);
	if (csize - asize >= MINBLOCKSIZE) {
		void *next_bp;

		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		next_bp = NEXT_BLKP(bp);
		PUT(HDRP(next_bp), PACK(csize - asize, 0));
		PUT(FTRP(next_bp), PACK(csize - asize, 0));
		insert_free_block(next_bp);
	} else {
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

void *
mm_malloc(size_t size)
{
	size_t asize;
	size_t extendsize;
	void *bp;

	if (size == 0)
		return (NULL);

	asize = adjust_block_size(size);
	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)
		return (NULL);
	place(bp, asize);
	return (bp);
}

void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	NEXT_FREEP(bp) = NULL;
	PREV_FREEP(bp) = NULL;
	coalesce(bp);
}

void *
mm_realloc(void *ptr, size_t size)
{
	size_t asize;
	size_t oldsize;
	size_t copy_size;
	void *newptr;

	if (ptr == NULL)
		return (mm_malloc(size));
	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}

	asize = adjust_block_size(size);
	oldsize = GET_SIZE(HDRP(ptr));

	if (asize <= oldsize) {
		size_t remainder = oldsize - asize;

		if (remainder >= MINBLOCKSIZE) {
			void *split_bp;

			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			split_bp = NEXT_BLKP(ptr);
			PUT(HDRP(split_bp), PACK(remainder, 0));
			PUT(FTRP(split_bp), PACK(remainder, 0));
			NEXT_FREEP(split_bp) = NULL;
			PREV_FREEP(split_bp) = NULL;
			coalesce(split_bp);
		}
		return (ptr);
	}

	if (!GET_ALLOC(HDRP(NEXT_BLKP(ptr)))) {
		void *next_bp = NEXT_BLKP(ptr);
		size_t combined = oldsize + GET_SIZE(HDRP(next_bp));

		if (combined >= asize) {
			remove_free_block(next_bp);
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
			if (combined - asize >= MINBLOCKSIZE) {
				void *split_bp;

				PUT(HDRP(ptr), PACK(asize, 1));
				PUT(FTRP(ptr), PACK(asize, 1));
				split_bp = NEXT_BLKP(ptr);
				PUT(HDRP(split_bp), PACK(combined - asize, 0));
				PUT(FTRP(split_bp), PACK(combined - asize, 0));
				NEXT_FREEP(split_bp) = NULL;
				PREV_FREEP(split_bp) = NULL;
				insert_free_block(split_bp);
			}
			return (ptr);
		}
	}

	if (GET_SIZE(HDRP(NEXT_BLKP(ptr))) == 0) {
		size_t extra = ALIGN(MAX(asize - oldsize, CHUNKSIZE));

		if (mem_sbrk((intptr_t)extra) == (void *)-1)
			return (NULL);
		PUT(HDRP(ptr), PACK(oldsize + extra, 1));
		PUT(FTRP(ptr), PACK(oldsize + extra, 1));
		PUT(HDRP(NEXT_BLKP(ptr)), PACK(0, 1));
		if (oldsize + extra - asize >= MINBLOCKSIZE) {
			void *split_bp;

			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			split_bp = NEXT_BLKP(ptr);
			PUT(HDRP(split_bp), PACK(oldsize + extra - asize, 0));
			PUT(FTRP(split_bp), PACK(oldsize + extra - asize, 0));
			NEXT_FREEP(split_bp) = NULL;
			PREV_FREEP(split_bp) = NULL;
			insert_free_block(split_bp);
		}
		return (ptr);
	}

	newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);

	copy_size = oldsize - DSIZE;
	if (size < copy_size)
		copy_size = size;
	memcpy(newptr, ptr, copy_size);
	mm_free(ptr);
	return (newptr);
}

static bool
in_heap(const void *p)
{
	return (p >= mem_heap_lo() && p <= mem_heap_hi());
}

static bool
aligned(const void *p)
{
	return (((uintptr_t)p % DSIZE) == 0);
}

static void
checkblock(void *bp)
{
	if (!in_heap(bp))
		printf("Error: block %p outside heap\n", bp);
	if (!aligned(bp))
		printf("Error: block %p is not aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header/footer mismatch at %p\n", bp);
}

void
checkheap(bool verbose)
{
	void *bp;
	size_t free_blocks = 0;
	size_t listed_blocks = 0;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE || !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
		if (!GET_ALLOC(HDRP(bp))) {
			free_blocks++;
			if (!GET_ALLOC(HDRP(NEXT_BLKP(bp))) &&
			    GET_SIZE(HDRP(NEXT_BLKP(bp))) > 0)
				printf("Error: contiguous free blocks %p and %p not coalesced\n",
				    bp, NEXT_BLKP(bp));
		}
	}

	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	for (int i = 0; i < LISTLIMIT; i++) {
		for (bp = list_head(i); bp != NULL; bp = NEXT_FREEP(bp)) {
			listed_blocks++;
			if (!in_heap(bp))
				printf("Error: free list pointer %p outside heap\n", bp);
			if (GET_ALLOC(HDRP(bp)))
				printf("Error: allocated block %p in free list\n", bp);
			if (PREV_FREEP(bp) != NULL && NEXT_FREEP(PREV_FREEP(bp)) != bp)
				printf("Error: broken prev link at %p\n", bp);
		}
	}

	if (free_blocks != listed_blocks)
		printf("Error: free block count mismatch heap=%zu list=%zu\n",
		    free_blocks, listed_blocks);
}

static void
printblock(void *bp)
{
	size_t hsize = GET_SIZE(HDRP(bp));
	bool halloc = GET_ALLOC(HDRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}

	printf("%p: header [%zu:%c] footer [%zu:%c]\n",
	    bp,
	    hsize, halloc ? 'a' : 'f',
	    GET_SIZE(FTRP(bp)), GET_ALLOC(FTRP(bp)) ? 'a' : 'f');
}

import shutil
import tempfile
from pathlib import Path

from tests.public.fixtures import compile_c_program, make_test_result, run_program


HARNESS = r"""
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

static int fail(const char *msg) {
    fprintf(stderr, "%s\n", msg);
    return 1;
}

int main(void) {
    mem_init();
    mem_reset_brk();
    if (mm_init() != 0) {
        return fail("mm_init failed");
    }

    if (mm_malloc(0) != NULL) {
        return fail("malloc(0) should return NULL");
    }

    mm_free(NULL);

    unsigned char *p = mm_malloc(24);
    if (p == NULL) {
        return fail("initial malloc failed");
    }
    for (int i = 0; i < 24; i++) {
        p[i] = (unsigned char)(i + 1);
    }

    unsigned char *q = mm_realloc(p, 80);
    if (q == NULL) {
        return fail("grow realloc failed");
    }
    for (int i = 0; i < 24; i++) {
        if (q[i] != (unsigned char)(i + 1)) {
            return fail("realloc grow did not preserve bytes");
        }
    }

    unsigned char *r = mm_realloc(NULL, 32);
    if (r == NULL) {
        return fail("realloc(NULL, n) should behave like malloc");
    }
    memset(r, 0xAB, 32);

    unsigned char *s = mm_realloc(q, 16);
    if (s == NULL) {
        return fail("shrink realloc failed");
    }
    for (int i = 0; i < 16; i++) {
        if (s[i] != (unsigned char)(i + 1)) {
            return fail("realloc shrink did not preserve prefix");
        }
    }

    if (mm_realloc(r, 0) != NULL) {
        return fail("realloc(ptr, 0) should return NULL");
    }

    mm_free(s);
    mem_deinit();
    return 0;
}
"""


def test_allocator_api_semantics(workspace):
    with tempfile.TemporaryDirectory() as tmpdir:
        tmp = Path(tmpdir)
        for name in ["mm.c", "mm.h", "memlib.c", "memlib.h", "config.h"]:
            shutil.copy(workspace / name, tmp / name)
        (tmp / "allocator_api_harness.c").write_text(HARNESS)

        success, error = compile_c_program(tmp, target="allocator_api_harness", makefile=False)
        if not success:
            return make_test_result(False, "compiled harness", "compilation failed", error)

        code, stdout, stderr = run_program(
            tmp / "allocator_api_harness",
            cwd=tmp,
            timeout=30,
            use_docker=False,
        )
        output = (stdout + stderr).strip()
        if code != 0:
            return make_test_result(False, "exit code 0", f"exit code {code}", output)

        return make_test_result(True, "exit code 0", "allocator API semantics passed", None)

